mapper.select:
select

from biz_claim a left join sys_user b on a.claimer = b.account


        and (a.createtime between CONCAT(#{startTime},' 00:00:00') and CONCAT(#{endTime},' 23:59:59'))


        and a.status = #{bizClaim.status}


        and a.type = #{bizClaim.type}


        and a.name = #{bizClaim.name}


        and a.phone = #{bizClaim.phone}


        and a.claimer = #{bizClaim.claimer}


        and a.openid = #{bizClaim.openid}



        and a.id = #{bizClaim.id}


ORDER BY a.createtime desc

select t.createtime,txm.title,t.type from biz_claim t left join biz_xcx_maintenance txm on txm.id=t.maintenance_id
where t.openid=#{openId}

    and t.type=#{type}

order by t.createtime desc
